	 	 	 parameters.A[3*i+2,3*(i+0)+2]  = -( parameters.Nc[i+0]*parameters.mu_n[i]*parameters.q*(1.0 - 0.5*parameters.q*(parameters.u[(3*i)+0] - parameters.u[3*(i+1)+0])/(parameters.T*parameters.kB) + 0.0833333333333333*parameters.q**2*(parameters.u[(3*i)+0] - parameters.u[3*(i+1)+0])**2/(parameters.T**2*parameters.kB**2) - 0.00138888888888889*parameters.q**4*(parameters.u[(3*i)+0] - parameters.u[3*(i+1)+0])**4/(parameters.T**4*parameters.kB**4) + 3.30687830687831e-5*parameters.q**6*(parameters.u[(3*i)+0] - parameters.u[3*(i+1)+0])**6/(parameters.T**6*parameters.kB**6))*np.exp(parameters.q*(-parameters.Ec[i+0] + parameters.u[(3*i)+0] - parameters.u[(3*i)+2])/(parameters.T*parameters.kB))/parameters.dx + parameters.Nc[i+0]*parameters.mu_n[i]*parameters.q*(1.0 - 0.5*parameters.q*(parameters.u[(3*i)+0] - parameters.u[3*(i-1)+0])/(parameters.T*parameters.kB) + 0.0833333333333333*parameters.q**2*(parameters.u[(3*i)+0] - parameters.u[3*(i-1)+0])**2/(parameters.T**2*parameters.kB**2) - 0.00138888888888889*parameters.q**4*(parameters.u[(3*i)+0] - parameters.u[3*(i-1)+0])**4/(parameters.T**4*parameters.kB**4) + 3.30687830687831e-5*parameters.q**6*(parameters.u[(3*i)+0] - parameters.u[3*(i-1)+0])**6/(parameters.T**6*parameters.kB**6))*np.exp(parameters.q*(-parameters.Ec[i-1] + parameters.u[(3*i)+0] - parameters.u[(3*i)+2])/(parameters.T*parameters.kB))/parameters.dx )
