def first_update_b(Ua, Ub):

	 for i in range(0, parameters.n):
	 	 if (i==0) :
	 	 	 #################
	 	 	 ###  left ###
	 	 	 #################
	 	 	 parameters.b[3*i+0] =  (U_Ohm(parameters.C[0             ], parameters.Ec[0             ], parameters.Ev[0             ], parameters.Nc[0             ], parameters.Nv[0             ]) + Ua) - 2*parameters.u[(3*i)+0] + parameters.u[3*(i+1)+0] + parameters.dx**2*parameters.q*(parameters.C[i] - parameters.Nc[i+0]*np.exp(parameters.q*(-parameters.Ec[i+0] + parameters.u[(3*i)+0] - parameters.u[(3*i)+2])/(parameters.T*parameters.kB)) + parameters.Nv[i+0]*np.exp(parameters.q*(parameters.Ev[i+0] - parameters.u[(3*i)+0] + parameters.u[(3*i)+1])/(parameters.T*parameters.kB)))/parameters.Epsilon[i]
	 	 	 parameters.b[3*i+1] =  parameters.u[(3*i)+1]
	 	 	 parameters.b[3*i+2] =  parameters.u[(3*i)+2]
	 	 elif(i==parameters.n-1):
	 	 	 #################
	 	 	 ###  right ###
	 	 	 #################
	 	 	 parameters.b[3*i+0] =  (U_Ohm(parameters.C[parameters.n-1], parameters.Ec[parameters.n-1], parameters.Ev[parameters.n-1], parameters.Nc[parameters.n-1], parameters.Nv[parameters.n-1]) + Ub) - 2*parameters.u[(3*i)+0] + parameters.u[3*(i-1)+0] + parameters.dx**2*parameters.q*(parameters.C[i] - parameters.Nc[i+0]*np.exp(parameters.q*(-parameters.Ec[i+0] + parameters.u[(3*i)+0] - parameters.u[(3*i)+2])/(parameters.T*parameters.kB)) + parameters.Nv[i+0]*np.exp(parameters.q*(parameters.Ev[i+0] - parameters.u[(3*i)+0] + parameters.u[(3*i)+1])/(parameters.T*parameters.kB)))/parameters.Epsilon[i]
	 	 	 parameters.b[3*i+1] =  parameters.u[(3*i)+1]
	 	 	 parameters.b[3*i+2] =  parameters.u[(3*i)+2]
	 	 else:
	 	 	 #################
	 	 	 ###  center ###
	 	 	 #################
	 	 	 parameters.b[3*i+0] =  -2*parameters.u[(3*i)+0] + parameters.u[3*(i+1)+0] + parameters.u[3*(i-1)+0] + parameters.dx**2*parameters.q*(parameters.C[i] - parameters.Nc[i+0]*np.exp(parameters.q*(-parameters.Ec[i+0] + parameters.u[(3*i)+0] - parameters.u[(3*i)+2])/(parameters.T*parameters.kB)) + parameters.Nv[i+0]*np.exp(parameters.q*(parameters.Ev[i+0] - parameters.u[(3*i)+0] + parameters.u[(3*i)+1])/(parameters.T*parameters.kB)))/parameters.Epsilon[i]
	 	 	 parameters.b[3*i+1] =  parameters.u[(3*i)+1]
	 	 	 parameters.b[3*i+2] =  parameters.u[(3*i)+2]

	 return None



